INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d2aef943-d551-456d-b2f7-bd530c268780', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Mesh VPN over WireGuard$q$, $q$Creates direct, encrypted peer-to-peer tunnels between devices using the WireGuard protocol instead of routing all traffic through a central VPN server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$MagicDNS$q$, $q$Automatically assigns memorable, private hostnames to every device on the tailnet so users can connect by name instead of tracking IP addresses.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Identity-based ACLs$q$, $q$Defines access policies based on user identity, device attributes, and tags rather than broad network-level trust, supporting a zero-trust security model.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Subnet routers and exit nodes$q$, $q$Bridges non-Tailscale networks into the tailnet or routes a device's internet traffic through another node, useful for reaching legacy infrastructure or remote regions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Tailscale SSH$q$, $q$Provides certificate-based SSH access to machines on the tailnet without distributing or managing SSH keys manually.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$SSO and SCIM provisioning$q$, $q$Integrates with identity providers such as Okta, Google Workspace, and Microsoft Entra for single sign-on and automated user provisioning on paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Kubernetes operator$q$, $q$Connects Kubernetes clusters and workloads into the tailnet, simplifying secure access to services running inside a cluster.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Funnel and Serve$q$, $q$Exposes a local service to teammates on the tailnet or to the public internet over HTTPS without configuring a reverse proxy or opening firewall ports.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Audit logs and network flow logs$q$, $q$Records administrative actions and connection-level traffic data for compliance, troubleshooting, and security monitoring on higher tiers.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Cross-platform native apps$q$, $q$Ships dedicated clients for macOS, Windows, Linux, iOS, and Android, plus a web-based admin console for managing the entire tailnet.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Fast setup with minimal network configuration compared to traditional VPNs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Built on the well-regarded, high-performance WireGuard protocol$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Generous free Personal plan for individuals and small personal networks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Granular identity-based access controls support a genuine zero-trust model$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Broad platform support across desktop, mobile, servers, and Kubernetes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Per-user pricing on business plans can get expensive as headcount grows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Relies on Tailscale's hosted coordination server unless self-hosting Headscale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Interface and documentation are primarily English-only$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Advanced features like audit logs and JIT access require the higher-priced Premium tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Occasional connections fall back to relay servers, adding latency versus a direct link$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Is Tailscale free to use?$q$, $q$Yes. Tailscale offers a free Personal plan that covers up to six users with unlimited user-owned devices, making it usable at no cost for individuals and small personal setups.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$What protocol does Tailscale use for encryption?$q$, $q$Tailscale is built on top of WireGuard, an open-source VPN protocol known for strong modern cryptography and high performance with a small codebase.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Does Tailscale require opening ports on my router?$q$, $q$No. Tailscale uses NAT traversal techniques to establish direct connections between devices behind routers and firewalls without manual port forwarding in most cases.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Can Tailscale be self-hosted?$q$, $q$The Tailscale client is open source, and an independent open-source project called Headscale implements a self-hosted alternative to Tailscale's coordination server, though it is not officially supported by Tailscale itself.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$What is the difference between the Standard and Premium plans?$q$, $q$Standard adds business features like SCIM provisioning and device posture integrations on top of the free tier, while Premium adds advanced capabilities such as just-in-time access, network flow logs, log streaming, and priority support.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Securing remote employee access$q$, $q$Connects remote and hybrid employees to internal tools, databases, and internal web apps without a traditional corporate VPN concentrator.$q$, $q$IT and security teams at distributed companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Bridging multi-cloud and hybrid infrastructure$q$, $q$Wires together servers running across multiple cloud providers and on-prem data centers into a single flat, private network.$q$, $q$DevOps and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Accessing a home lab or personal server remotely$q$, $q$Lets an individual reach a home NAS, media server, or personal Raspberry Pi from anywhere without exposing it to the public internet.$q$, $q$Developers and homelab hobbyists$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Securing CI/CD pipeline connectivity$q$, $q$Gives ephemeral build agents and CI runners scoped, temporary network access to internal resources without static credentials or VPN configs.$q$, $q$Engineering teams running automated pipelines$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Personal$q$, $q$Free$q$, $q$Free forever$q$, $q$["Up to 6 users","Unlimited user-owned devices","3 ACL groups","50 tagged resources","Basic SSH and Kubernetes support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Standard$q$, $q$$8 per user/month$q$, $q$Per user, per month$q$, $q$["Unlimited users","SCIM deployment","10 ACL groups","MDM configuration","Device posture integrations","Advanced user roles"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Premium$q$, $q$$18 per user/month$q$, $q$Per user, per month$q$, $q$["Everything in Standard","300 ACL groups","Just-in-time access","Advanced SSH","Network flow logs","Log streaming","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Pay by invoice$q$, $q$["Everything in Premium","Custom device limits","Solutions Engineer support","Custom MSAs and SLAs","Dedicated professional services"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Tailscale is a zero-config mesh VPN built on top of the open-source WireGuard protocol. Rather than routing traffic through a central VPN server, Tailscale creates direct, encrypted peer-to-peer connections between every device on a private network, forming what the company calls a "tailnet." Devices authenticate using existing identity providers like Google, Microsoft, GitHub, or Okta, and once connected they can reach each other by stable, private IP addresses or MagicDNS hostnames regardless of where they physically sit.$q$, $q$The company was founded in 2019 and has grown into a widely used connectivity layer for engineering teams, positioning itself as a modern replacement for legacy corporate VPNs, complex SASE appliances, and manual bastion-host setups. Its pitch is that secure networking should not require dedicated network engineers, VPN concentrators, or firewall rule sprawl — installing the client and signing in is often enough to get a working private network in minutes.$q$, $q$Tailscale runs across desktop, mobile, server, and container environments, and it layers zero-trust access controls, identity-aware routing, and audit logging on top of the underlying WireGuard tunnels. It is used both by individuals connecting a handful of personal devices and by engineering organizations wiring together production infrastructure, Kubernetes clusters, CI/CD runners, and remote employee laptops into a single addressable network.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$who-tailscale-is-for$q$, $q$Who Tailscale Is For$q$, 2, ARRAY[$q$Tailscale is aimed at engineering, DevOps, and IT teams that need to connect distributed infrastructure and remote employees without standing up traditional VPN hardware. It suits organizations with hybrid or multi-cloud footprints — servers spread across AWS, on-prem data centers, and home labs — that want a single flat network without manual firewall and routing configuration on each hop.$q$, $q$It is also a strong fit for security-conscious teams that want to move toward a zero-trust model: access can be scoped per user, per device, or per resource using identity-based ACLs rather than broad network-level trust. Startups and small teams benefit from how quickly a working secure network can be stood up compared to configuring a self-managed VPN server.$q$, $q$Individual developers, homelab hobbyists, and remote workers are another core audience — the free Personal plan lets a single person securely reach their home NAS, personal servers, or a Raspberry Pi from anywhere without opening ports on their router or paying for infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that require a fully self-hosted, vendor-independent control plane may find Tailscale's managed coordination server (even though the client is open source) a dealbreaker; those teams often gravitate toward the open-source Headscale project instead, accepting more operational overhead in exchange for not depending on Tailscale's hosted infrastructure.$q$, $q$Very large teams with heavy per-seat usage should budget carefully, since business and enterprise pricing is charged per user rather than per device, and costs can climb as headcount grows; teams looking for a flat-rate, unlimited-user VPN may prefer other models. Teams that need built-in multi-language interface support should also be aware that the product and documentation are primarily in English.$q$, $q$Companies wanting a traditional hub-and-spoke corporate VPN with heavy content filtering, deep packet inspection, or on-prem appliance requirements may find Tailscale's peer-to-peer model, while more secure and flexible, a philosophical mismatch for existing network security policies built around a single choke point.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Tailscale provides a mesh VPN with direct, encrypted device-to-device connections using WireGuard, MagicDNS for human-readable hostnames instead of memorizing IP addresses, and automatic NAT traversal so devices behind routers and firewalls can still connect without manual port forwarding.$q$, $q$On top of connectivity, it layers identity-based access control lists (ACLs) for zero-trust policies, subnet routers and exit nodes for bridging non-Tailscale networks or routing traffic through a chosen egress point, Tailscale SSH for certificate-based server access without managing SSH keys, and Funnel/Serve for exposing local services to the internet or teammates securely.$q$, $q$Administrative features include SSO and SCIM provisioning for enterprise identity systems, device posture and MDM integrations, a Kubernetes operator for cluster networking, network flow logs and audit logging for compliance visibility, and a centralized admin console for managing devices, users, and tagged infrastructure resources.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', $q$the-tailscale-experience$q$, $q$The Tailscale Experience$q$, 2, ARRAY[$q$Users consistently describe the day-to-day experience as close to "install and forget." Native apps exist for macOS, Windows, Linux, iOS, and Android, and once a device joins a tailnet it simply appears as a reachable peer — no VPN dashboards to reconnect to, no manual IP configuration, and connections that persist reliably across network changes like switching from Wi-Fi to cellular.$q$, $q$The admin console gives IT and security teams a single place to view every device on the network, apply ACL policies, review audit logs, and manage tagged servers or service accounts, which keeps operational overhead low even as a tailnet scales from a handful of personal devices to thousands of corporate endpoints.$q$, $q$Because it is built on WireGuard, performance is generally fast with low overhead, and the peer-to-peer architecture means traffic between two devices in the same office or cloud region does not need to detour through a distant relay server except when direct connections cannot be established, in which case Tailscale's DERP relay servers keep the connection working, just with a small latency cost.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c69ab424-480e-464f-8a10-266de3ca5887', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
