INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Drag-and-Drop Course Builder$q$, $q$Structure curricula with video, text, PDFs, images, and quizzes across modules and lessons without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Teachable Payments & Checkout$q$, $q$Built-in payment processing with one-click order bumps, upsells, coupons, and automatic global sales tax and VAT collection.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$AI Course Creation Tools$q$, $q$Generate course outlines, lesson text, and quizzes with AI to speed up curriculum production from a course name and description.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Video Subtitles & Translation$q$, $q$Automatically generate video captions and translate them into dozens of languages to reach a global student audience.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Drip Content & Progress Tracking$q$, $q$Release lessons on a schedule and monitor student completion and engagement across courses.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Certificates of Completion$q$, $q$Award students automated completion certificates when they finish a course or module.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Affiliate Program Management$q$, $q$Recruit and pay affiliates to promote courses directly from the platform on eligible plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Mobile Learning Apps$q$, $q$Give students access to purchased courses through iOS and Android apps for on-the-go learning.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Team & Admin Permissions$q$, $q$Add multiple admin seats with configurable permissions for co-instructors and staff on higher-tier plans.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Fast to set up a first course with a straightforward, guided course builder$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Strong built-in payments with automatic global sales tax and VAT handling$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$AI tools for outlines, lesson writing, quizzes, and video translation speed up production$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Reliable, polished checkout and student learning experience$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Flexible plan tiers that scale from solo creators to multi-instructor teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$No permanent free plan, and the Starter plan carries a 7.5% transaction fee$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Limited control over lesson and page layout compared to page-builder competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Assessment options are thin for complex quizzes, file uploads, or open-ended grading$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Community and membership features are less developed than dedicated platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Customer support responsiveness and checkout reliability during peak sales are inconsistently reviewed$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Does Teachable have a free plan?$q$, $q$No. Teachable does not offer a permanent free plan, but every paid plan includes a 7-day free trial and a 30-day money-back guarantee.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$What transaction fees does Teachable charge?$q$, $q$The entry-level Starter plan charges a 7.5% transaction fee on sales. The Builder, Growth, and Custom plans charge 0% transaction fees, relying instead on standard payment processing costs.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Can I sell coaching, memberships, or digital downloads, not just courses?$q$, $q$Yes. Beyond structured courses, Teachable supports selling coaching sessions, memberships, and digital downloads through the same checkout and product tools.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Does Teachable support multiple languages?$q$, $q$Yes. Creators can set a student-facing language for their school from a list that includes English, Spanish, French, German, Portuguese, Italian, Arabic, Japanese, Thai, Chinese, and Turkish, and can auto-translate video subtitles into many more languages.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Who owns Teachable?$q$, $q$Teachable is owned by Hotmart Company, a global creator-economy company that acquired Teachable in 2020 and also operates the Hotmart platform.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Launching a Signature Online Course$q$, $q$Package expertise into a structured, video-based course with quizzes and certificates, then sell it directly through a built-in checkout page.$q$, $q$Solo coaches, consultants, and subject-matter experts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Selling Group Coaching and Cohorts$q$, $q$Combine course content with scheduled coaching or cohort access, using drip scheduling and student progress tracking to manage delivery.$q$, $q$Coaches and consultants running cohort-based programs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Scaling a Multi-Instructor Course Business$q$, $q$Manage multiple products, add team members with defined admin permissions, and track sales across a growing catalog of courses.$q$, $q$Small teams and established course businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Expanding Course Sales Internationally$q$, $q$Reach students in different regions using built-in language options, translated video subtitles, and automatic global tax and VAT collection.$q$, $q$Creators selling to an international student base$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Starter$q$, $q$$39/month (or $29/month billed annually)$q$, $q$Monthly or Annual$q$, $q$["Up to 5 products and 100 active students","7.5% transaction fee","AI course creation tools","Mobile apps and global payments","Upsells and completion certificates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Builder$q$, $q$$89/month (or $69/month billed annually)$q$, $q$Monthly or Annual$q$, $q$["Up to 10 products and 1,000 active students","0% transaction fee","All Starter features","Affiliate program","Real-time support and community access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Growth$q$, $q$$189/month (or $139/month billed annually)$q$, $q$Monthly or Annual$q$, $q$["Up to 50 products and 5,000 active students","0% transaction fee","Up to 5 admin users","Branding removal and custom permissions","Free subtitles and translations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$Custom$q$, $q$Contact for pricing$q$, $q$Annual$q$, $q$["Designed for high-volume businesses","Everything in Growth","Dedicated success manager","White-glove onboarding","Priority SLA support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Teachable is a cloud-based platform for building and selling online courses, coaching programs, and digital downloads. Originally launched under the name Fedora, it rebranded to Teachable and grew into one of the best-known names in the creator-economy course space before being acquired by Hotmart Company in 2020.$q$, $q$The platform bundles course hosting, a drag-and-drop curriculum builder, checkout and payment processing, and lightweight marketing tools into a single subscription, so a creator can go from an idea to a sellable product without stitching together separate hosting, payment, and email tools.$q$, $q$Teachable competes most directly with Thinkific, Kajabi, and Podia. It differentiates itself with strong built-in payments, including automated global tax handling, and a straightforward course builder aimed at speed and simplicity rather than deep marketing-funnel or website-design flexibility.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$who-teachable-is-for$q$, $q$Who Teachable Is For$q$, 2, ARRAY[$q$Individual coaches, consultants, authors, and subject-matter experts who want to turn knowledge into a paid course or coaching offer are Teachable's core audience, especially those who don't want to hire developers or manage separate software for content, payments, and student communication.$q$, $q$Small teams and growing course businesses that have outgrown a single free lead-magnet course also fit well, particularly on the Builder and Growth plans, which add multiple products, additional admin seats, and more sophisticated student-management tools.$q$, $q$Creators who value fast setup and a clean, reliable checkout and student experience over pixel-level design control tend to be happiest, as do those selling internationally who want built-in sales tax and VAT collection handled automatically.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Creators who need precise control over lesson layout, custom page design, or a full marketing website should look elsewhere, since Teachable's lesson editor is largely limited to stacking standard content blocks in a fixed order.$q$, $q$Businesses that need advanced assessment types, such as file-upload submissions, open-ended grading, or branching quizzes, or that want a robust built-in community and membership experience, will likely find Teachable's tools thinner than dedicated LMS or community platforms.$q$, $q$Very early-stage creators testing an idea on a tight budget should be cautious too, since there is no permanent free plan, and the entry-level Starter plan's 7.5% transaction fee can outweigh the cost of upgrading once sales start to grow.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Teachable offers a drag-and-drop course builder supporting video, PDFs, text lessons, quizzes, and completion certificates, along with drip-content scheduling and student progress tracking so creators can structure a curriculum without any coding.$q$, $q$Built-in Teachable Payments handles checkout, one-click order bumps and upsells, coupon codes, and an affiliate program on higher-tier plans, while also automatically collecting sales tax and VAT across regions and issuing fast payouts to creators.$q$, $q$AI-assisted tools help speed up production, including a course outline and curriculum generator, an AI lesson-writing assistant, and an AI quiz generator, plus automatic video subtitles and translation. Mobile apps, team permissions, and custom branding round out the plans for larger operations.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', $q$the-teachable-experience$q$, $q$The Teachable Experience$q$, 2, ARRAY[$q$New users generally report being able to publish a first course within days, thanks to the guided course builder and pre-built checkout and sales pages that require no design or development work to get started.$q$, $q$Reviews of the product tend to be polarized: many creators praise the smooth student experience, dependable payments, and helpful AI content tools, while other reviewers describe frustration with support responsiveness and occasional checkout reliability issues during high-traffic promotions.$q$, $q$Overall, Teachable suits creators who want a dependable, largely hands-off backend for selling structured content and coaching, in exchange for less flexibility than page-builder-heavy competitors offer to creators chasing highly customized brand experiences.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('331c1d71-2a89-499a-9b96-e38d4d4f0feb', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
