INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Drag-and-drop career site builder$q$, $q$A visual editor with pre-built blocks for job listings, culture pages, video headers, and testimonials, letting non-technical teams ship a branded careers site without a developer.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Applicant tracking pipelines$q$, $q$Customizable hiring stages, structured interview kits, and shared scorecards so hiring teams collaborate on the same candidate data instead of email threads.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$AI Co-pilot$q$, $q$AI-assisted job ad writing, candidate matching against talent pools, evaluation against hiring criteria, interview question suggestions, and CV summarization.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Talent pool and CRM$q$, $q$A searchable database of past applicants and passive candidates that recruiters can revisit and nurture for future openings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Automation and triggers$q$, $q$Rule-based automations that move candidates between stages, send scheduled emails, or alert hiring managers without manual follow-up.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Multilingual career sites and localization$q$, $q$Interface and career-site content can be localized into multiple languages, with AI-assisted translation of job content for global hiring.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Analytics and reporting$q$, $q$Dashboards covering pipeline health, source performance, and time-to-hire to help teams see where hiring is slowing down.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Onboarding tools$q$, $q$Workflows that extend past the offer stage to help new hires get set up and integrated with the company.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Integrations marketplace$q$, $q$Connections to job boards, background-check providers, e-signature tools, assessments, and broader HR tech stacks.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Modern, visually polished career site builder that doesn't require developer help$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Intuitive interface with a short learning curve for recruiters and hiring managers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Responsive customer support frequently praised in user reviews$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$AI Co-pilot adds practical time savings for job ad writing, matching, and translation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Unlimited users and job postings included rather than per-seat pricing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Pricing is quote-based and not published, making it hard to compare costs upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Sold on annual contracts with no month-to-month or pay-as-you-go option$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Customization options outside the career site builder can feel limited$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$No dedicated native mobile apps, only a responsive web experience$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Some automated notifications, like emails to existing candidates on new postings, aren't fully configurable$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$What is Teamtailor used for?$q$, $q$Teamtailor is an applicant tracking system and employer branding platform used to manage recruitment pipelines, build a branded careers site, and collaborate on hiring decisions in one place.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Does Teamtailor offer a free trial?$q$, $q$Teamtailor is commonly offered with a free trial period so teams can evaluate the platform before committing to an annual contract; exact trial terms are best confirmed directly with Teamtailor since they can change.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$How is Teamtailor priced?$q$, $q$Teamtailor uses custom, quote-based pricing tied to company size and the number of concurrent open roles rather than a fixed per-seat fee, and typically requires an annual contract.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Does Teamtailor have a mobile app?$q$, $q$Teamtailor does not offer dedicated native iOS or Android apps; it is designed as a responsive web application that works on mobile browsers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$What languages does Teamtailor support?$q$, $q$Teamtailor's interface and career sites can be localized into multiple languages, including English, Swedish, Danish, German, Spanish, Finnish, French, Italian, Dutch, Norwegian, and Portuguese (Brazilian), among others.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Building an employer brand without developer resources$q$, $q$A people team uses the drag-and-drop career site builder to launch and maintain a professional, on-brand jobs page featuring culture content and testimonials, without needing engineering support.$q$, $q$HR and talent acquisition teams at growing companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Running structured, collaborative hiring pipelines$q$, $q$Hiring managers and recruiters use shared interview kits and scorecards to evaluate candidates consistently and move them through pipeline stages together.$q$, $q$Recruiting teams and hiring managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Hiring across multiple countries and languages$q$, $q$An international company localizes its career site and internal interface into several languages and uses AI-assisted translation for job postings to reach candidates in different markets.$q$, $q$Multinational or distributed organizations$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Automating repetitive recruiting admin work$q$, $q$A talent team sets up triggers to automatically move candidates, send status emails, and notify stakeholders, reducing manual follow-up during high-volume hiring periods.$q$, $q$Recruiting operations teams handling high applicant volume$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Small to Midsize$q$, $q$Custom pricing (contact sales)$q$, $q$Annual contract$q$, $q$["Unlimited users","Unlimited job postings","Career site builder","AI Co-pilot","Integrations marketplace","Customer support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$Enterprise$q$, $q$Custom pricing (contact sales)$q$, $q$Annual contract$q$, $q$["Unlimited users","Unlimited job postings","Advanced analytics and reporting","Dedicated support","Expanded integrations and security options","Multi-market career site localization"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Teamtailor is a Swedish applicant tracking system (ATS) and employer branding platform founded in 2013 and headquartered in Stockholm. It was built as a "next generation" alternative to older, workflow-only recruiting software, pairing the core mechanics of an ATS with tools for building a polished, on-brand careers site. The company now serves organizations across dozens of countries, ranging from small scale-ups to large enterprises with thousands of employees.$q$, $q$The product's defining idea is that recruiting is as much a marketing problem as an operations problem. Rather than treating the careers page as an afterthought bolted onto a job board, Teamtailor gives recruiting and people teams a visual, drag-and-drop site editor so they can present culture, benefits, and open roles without needing a developer. That career site sits on top of a full pipeline, interview, and collaboration toolset, so hiring managers and recruiters work from a shared, searchable database of candidates rather than a maze of spreadsheets and email threads.$q$, $q$More recently, Teamtailor has layered an AI Co-pilot across the platform, adding candidate matching against talent pools, evaluation against hiring criteria, interview question suggestions, CV summarization, and AI-assisted job ad writing and translation. Combined with a large marketplace of integrations for job boards, background checks, e-signing, and HR systems, the platform aims to be a single hub that covers sourcing, screening, employer branding, and onboarding.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$who-teamtailor-is-for$q$, $q$Who Teamtailor Is For$q$, 2, ARRAY[$q$Teamtailor is aimed squarely at growing companies that treat hiring as a brand-building exercise, not just a back-office task. Startups and scale-ups that are hiring across multiple markets tend to be a strong fit, since the tool was built to make a small people team look and operate like a much larger one. Recruiting and talent acquisition teams without in-house developers or designers benefit most, because the career site builder removes the need for custom web work to keep the jobs page current and on-brand.$q$, $q$Companies with distributed or international hiring also fit well, thanks to built-in localization for both the internal interface and candidate-facing career sites, along with AI-assisted translation of job content. Organizations that care about structured, collaborative hiring decisions - shared scorecards, interview kits, automated candidate communication - will find the workflow tooling maps closely to modern hiring best practices rather than replicating a legacy paper trail.$q$, $q$It also suits companies that expect to scale their hiring volume over time, since pricing and account structure are built around concurrent open roles and company size tiers rather than a fixed per-seat model that gets expensive as teams add more hiring managers and interviewers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teamtailor is a weaker match for solo founders, very small businesses, or companies that hire only occasionally, since the platform is sold on annual contracts rather than flexible month-to-month or pay-as-you-go terms, and pricing is quote-based rather than published, which makes it hard to test at a low commitment level. Organizations that need to keep costs minimal and predictable from day one may prefer a lighter, self-serve ATS instead.$q$, $q$Enterprises with deep, highly specific compliance or reporting requirements - for example, heavy OFCCP or EEOC reporting obligations in regulated US hiring, or tight integration with a specific legacy HRIS - should validate those workflows carefully in a demo before committing, since Teamtailor's roots and strongest customer base are in Europe and general commercial hiring rather than US government-contractor compliance. Companies that already have a heavily customized HR tech stack with rigid integration requirements may also find the switching effort nontrivial.$q$, $q$Finally, teams that specifically want native mobile apps for recruiters and hiring managers should be aware that Teamtailor operates as a responsive web application rather than dedicated iOS or Android apps, which can matter for interviewers who lean on a phone for on-the-go candidate reviews.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Teamtailor is its career site builder, a drag-and-drop editor with pre-built content blocks - job listings, team and culture pages, video headers, testimonials, and custom pages - that lets non-technical teams ship a professional careers site without a developer, and localize it into multiple languages for different markets. Around that sits the core ATS: customizable pipelines, interview kits and scorecards, and a searchable talent pool so past applicants can be revisited for future openings.$q$, $q$The AI Co-pilot adds candidate matching and ranking against a role's requirements, AI-assisted job ad and question writing, CV summarization, and translation support for multilingual hiring. Automation triggers handle repetitive steps - moving candidates through stages, sending scheduled emails, or notifying hiring managers - while built-in analytics and reporting surface pipeline health, source performance, and time-to-hire metrics.$q$, $q$Structured onboarding workflows extend the platform past the offer stage, and a large marketplace of integrations connects job boards, background-check providers, e-signature tools, and broader HR systems into the same workspace.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', $q$the-teamtailor-experience$q$, $q$The Teamtailor Experience$q$, 2, ARRAY[$q$Day to day, Teamtailor is consistently described as clean, visual, and easy to pick up, which is a notable contrast with older ATS interfaces that require significant training. Recruiters and hiring managers generally report a short ramp-up time, and candidate-facing career sites are frequently singled out as a strength that helps smaller employer brands look more established.$q$, $q$Support is a recurring positive in customer feedback, with users citing responsive help during setup and ongoing use. The tradeoff some teams report is friction at the edges: customization can feel limited outside the main career site builder, calendar syncing occasionally misbehaves, and a handful of automated notifications - like emails to existing candidates when a new role is posted - are not fully configurable.$q$, $q$Overall, the experience favors teams that want a modern, marketing-forward front end paired with a capable but not maximally configurable backend ATS. Companies coming from spreadsheets or a bare-bones job board typically see the biggest jump in perceived professionalism and hiring team efficiency, while teams migrating from highly customized enterprise ATS platforms may notice a narrower, more opinionated feature set.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('18a08b34-9438-45e5-b3b9-9e7969c6add2', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
