INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Multiple Project Views$q$, $q$Switch between list, board (kanban), Gantt chart, and table views to plan and track tasks in the format that fits the team or project.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Time Tracking$q$, $q$Log billable and non-billable hours directly against tasks, feeding automatically into reporting, budgets, and client invoices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Resource Scheduling$q$, $q$See who is over- or under-allocated across active projects to balance workloads and plan capacity before it becomes a bottleneck.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Budgets and Financial Reporting$q$, $q$Track estimated versus actual project costs, monitor profitability, and get alerts when a project is at risk of going over budget.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Client Portals and Permissions$q$, $q$Give clients limited, controlled visibility into project progress without exposing internal comments, files, or financial detail.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Automation and Smart Forms$q$, $q$Automate repetitive status updates and task assignments, and convert incoming work requests into structured tasks via forms.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Invoicing and Accounting Integrations$q$, $q$Generate client invoices from tracked time and connect to accounting tools such as QuickBooks to streamline billing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$TeamworkAI$q$, $q$AI-assisted features that help summarize project activity, draft updates, and surface suggested next steps within projects.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Project Templates$q$, $q$Reusable templates for recurring client engagements speed up project setup and keep delivery processes consistent.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Third-Party Integrations$q$, $q$Connect with 150-plus tools, including HubSpot, Salesforce, Slack, and Google Workspace, to fit into an existing operational stack.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Combines project delivery with time tracking, budgeting, and profitability reporting in one workspace$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Client portals and permission controls are well suited to agency-client relationships$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Resource scheduling and capacity planning help balance workloads across multiple projects$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Deep integration ecosystem, including accounting tools like QuickBooks, for client-services workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Mobile apps for iOS and Android let teams log time and check status away from a desk$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Steeper learning curve than lightweight task managers due to the breadth of features$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Free plan is tightly capped on users, projects, and storage, limiting long-term use for growing teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Per-user pricing on higher tiers can become expensive as teams scale past a handful of seats$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Advanced financial and resourcing features, custom reports, and SSO are reserved for higher-priced or custom-quoted plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Less suited to software development teams needing deep agile/sprint tooling than dedicated dev-focused tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$What is Teamwork.com used for?$q$, $q$Teamwork.com is a project management and professional services automation (PSA) platform used mainly by agencies and client-services businesses to plan projects, track billable time, manage resources and budgets, and report on profitability.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Does Teamwork.com have a free plan?$q$, $q$Yes, Teamwork.com offers a free plan limited to a small number of users, projects, and storage, alongside paid plans that unlock higher limits and more advanced features, with a 30-day free trial available on paid tiers.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$How much does Teamwork.com cost?$q$, $q$Paid plans start at $9.99 per user per month when billed annually for the entry-level tier, with higher tiers priced per user per month and the top enterprise tiers requiring a custom quote from sales.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Is Teamwork.com good for agencies?$q$, $q$Teamwork.com is built with agencies in mind, offering client portals, budgeting, retainer tracking, and billable time reporting alongside standard project management features, which is why it is popular with marketing, IT, and consulting agencies.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Does Teamwork.com have mobile apps?$q$, $q$Yes, Teamwork.com provides mobile apps for iOS and Android so team members can view tasks, update status, and log time from a phone or tablet.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Managing Multiple Client Projects$q$, $q$Agencies running several concurrent client engagements use Teamwork.com to track deadlines, deliverables, and ownership across projects in one workspace.$q$, $q$Marketing, creative, and digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Tracking Billable Time and Profitability$q$, $q$Teams log billable and non-billable hours against tasks and compare estimated versus actual costs to see whether a project is staying profitable.$q$, $q$Consulting and professional services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Balancing Team Capacity$q$, $q$Resource scheduling views help operations leads spot over-allocated staff and redistribute work before deadlines slip.$q$, $q$Project and resource managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Collaborating With External Clients$q$, $q$Client portals give customers visibility into project progress and approvals without exposing internal discussion or budgets.$q$, $q$Client-facing account and delivery teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, $q$["Up to 5 users","Up to 5 projects","100MB storage","Task, list, board, and Gantt views","Time logging","100 automations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Basics$q$, $q$$9.99/user/month billed annually$q$, $q$Monthly or annual$q$, $q$["Up to 300 projects","100GB storage","Multiple project views","Unlimited templates","Billable time tracking","TeamworkAI access","30-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Accelerate$q$, $q$$24.99/user/month billed annually$q$, $q$Monthly or annual$q$, $q$["Up to 600 projects","250GB storage","Smart forms for work requests","20,000 automations","Team capacity planning and time budgets","Client invoicing and HubSpot/QuickBooks integration","30-day free trial"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Optimize / Enterprise$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Unlimited projects","500GB-1000GB storage","Resource scheduling by role or skill","Multi-currency budget tracking","Salesforce and NetSuite integration","Advanced security, SSO, and dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Teamwork.com is a project and client-work management platform founded in 2007 in Cork, Ireland, where it remains headquartered. It began as an internal tool built by a web design agency that needed better visibility into client projects, deadlines, and billable hours, and it has since grown into a company serving thousands of agencies and professional-services teams worldwide. Today Teamwork.com markets itself as "AI-powered PSA software built for profitability," reflecting a shift from a general task-tracking tool toward a fuller professional services automation suite.$q$, $q$The platform combines classic project management building blocks, tasks, boards, lists, Gantt charts, and milestones, with features aimed squarely at businesses that bill clients for their time. Time tracking, budgets, invoicing, resource scheduling, and profitability reporting sit alongside the project views, so a single workspace can show whether a project is on schedule and whether it is still making money. Client-facing features like portals and permission controls let agencies collaborate with customers without exposing internal chatter or financial detail.$q$, $q$Teamwork.com competes with a broad field of project and work management tools, from Asana and Monday.com to PSA-focused products like Kantata and Productive. Its differentiator is the tight coupling of project delivery with the financial side of client services work: budgets, retainers, and utilization reporting are treated as first-class citizens rather than bolt-ons. Recent additions of TeamworkAI and AI-driven automation continue that trajectory, aiming to help teams plan capacity and flag at-risk budgets earlier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$who-teamwork-is-for$q$, $q$Who Teamwork Is For$q$, 2, ARRAY[$q$Teamwork.com is built primarily for agencies and professional services businesses that bill clients by the hour or by project, including marketing and creative agencies, software and IT consultancies, architecture and engineering firms, and accounting or business-advisory practices. These teams typically juggle several client projects at once and need one place to see delivery status, team capacity, and profitability together.$q$, $q$It also suits operations and project leads at small to mid-sized companies (roughly 10 to a few hundred people) who need more structure than a simple task list but do not want the overhead of enterprise software. Teams that already track billable hours, negotiate retainers, or produce client invoices tend to get the most value, since those workflows map directly onto Teamwork.com's budgeting and time-tracking features.$q$, $q$Client-facing teams that want to give customers limited visibility into project status, without granting access to internal comments or margins, are another strong fit. The client-permission model and portal features were clearly designed with agency-client relationships in mind, which is a less common emphasis among general-purpose project management tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo freelancers and very small teams with simple to-do lists rather than multi-stage client projects will likely find Teamwork.com more tool than they need; a lighter product such as Trello or a basic task app will feel faster to set up and cheaper to run. The free plan caps users, projects, and storage tightly enough that it functions more as a trial than a long-term free option for growing teams.$q$, $q$Organizations that do not bill clients for time, internal-only teams, product companies without external client work, or nonprofits, may not need the budgeting, invoicing, and profitability features that define Teamwork.com's positioning, and could get equivalent task management elsewhere for less money and less setup effort.$q$, $q$Software engineering teams looking for deep sprint planning, backlog grooming, and issue-tracking depth comparable to Jira or Linear should also look elsewhere, since Teamwork.com's task and board views are general-purpose rather than built around agile development ceremonies. Likewise, teams wanting the most affordable entry point at scale may find per-user pricing on the higher tiers adds up quickly once dozens of seats are involved.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Core project management covers list, board (kanban), Gantt chart, and table views of tasks, along with milestones, task dependencies, and reusable project templates so recurring client work can be spun up quickly. Built-in time tracking lets team members log billable and non-billable hours directly against tasks, feeding into reporting and invoicing rather than living in a separate timesheet tool.$q$, $q$Resource scheduling and capacity planning show who is over- or under-allocated across projects, while budgeting tools track estimated versus actual costs and flag projects at risk of going over budget. Client management features include portals and permission settings so external stakeholders can view progress without seeing internal discussion, plus invoicing and integrations with accounting tools like QuickBooks.$q$, $q$Automation rules reduce repetitive status updates and task assignments, and smart forms can turn incoming work requests into structured tasks. TeamworkAI adds AI-assisted features such as summarization and suggested next steps, and the platform connects to 150-plus third-party tools, including HubSpot, Salesforce, Slack, and Google Workspace, so it can sit inside an existing operational stack rather than replacing it.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$the-teamwork-experience$q$, $q$The Teamwork Experience$q$, 2, ARRAY[$q$New users generally describe Teamwork.com's interface as more detailed than lightweight task managers, which brings real power for budgeting and resourcing but also a steeper initial learning curve. Getting full value out of the platform, particularly the financial reporting, usually means spending real time on setup: defining project templates, budget types, and permission structures before rolling it out team-wide.$q$, $q$The product is available as a web application with companion iOS and Android mobile apps for logging time and checking task status on the go. Support options scale with plan tier, from self-serve help docs and community resources on lower tiers to a dedicated customer success manager and priority support on enterprise-level plans, reflecting the product's lean toward mid-market and larger client-services teams.$q$, $q$Because Teamwork.com started life as an agency's internal tool, its day-to-day feel still favors teams managing multiple concurrent client engagements over teams running a single internal roadmap. Migration paths and templates for agencies switching from spreadsheets, email, or simpler task tools are a recurring theme in its own marketing and support content, underscoring who the product is ultimately built to serve.$q$]::text[], 4);
